class WebAppLogger:
    def __init__(self, log_file):
        self.log_file = log_file
        self.setup_logger()

    def setup_logger(self):
        logging.basicConfig(filename=self.log_file, level=logging.INFO,
                            format='%(asctime)s - %(levelname)s - %(message)s')

